@Keep
class NativeBridge(
    private val activity: Activity,
    private val webView: WebView,
    private val preferences: SharedPreferences,
    private val onCameraPermission: (callbackId: String?) -> Unit,
    private val onNotificationPermission: (callbackId: String?) -> Unit
) {

    @JavascriptInterface
    fun getPlatform(): String {
        return "android"
    }

    @JavascriptInterface
    fun requestCameraAccess(callbackId: String?) {
        activity.runOnUiThread {
            onCameraPermission(callbackId)
        }
    }

    @JavascriptInterface
    fun requestPushPermission(callbackId: String?) {
        activity.runOnUiThread {
            onNotificationPermission(callbackId)
        }
    }

    @JavascriptInterface
    fun localStorageSet(key: String, value: String, callbackId: String?) {
        val result = try {
            preferences.edit().putString(key, value).apply()
            successPayload(true)
        } catch (e: Exception) {
            errorPayload(e.message ?: "LOCAL_STORAGE_SET_FAILED")
        }
        resolve(callbackId, result)
    }

    @JavascriptInterface
    fun localStorageGet(key: String, callbackId: String?) {
        val result = try {
            val value = preferences.getString(key, null)
            JSONObject().apply {
                put("success", true)
                put("value", value)
            }
        } catch (e: Exception) {
            errorPayload(e.message ?: "LOCAL_STORAGE_GET_FAILED")
        }
        resolve(callbackId, result)
    }

    @JavascriptInterface
    fun localStorageRemove(key: String, callbackId: String?) {
        val result = try {
            preferences.edit().remove(key).apply()
            successPayload(true)
        } catch (e: Exception) {
            errorPayload(e.message ?: "LOCAL_STORAGE_REMOVE_FAILED")
        }
        resolve(callbackId, result)
    }

    @JavascriptInterface
    fun localStorageClear(callbackId: String?) {
        val result = try {
            preferences.edit().clear().apply()
            successPayload(true)
        } catch (e: Exception) {
            errorPayload(e.message ?: "LOCAL_STORAGE_CLEAR_FAILED")
        }
        resolve(callbackId, result)
    }

    @JavascriptInterface
    fun localStorageKeys(callbackId: String?) {
        val result = try {
            val keys = preferences.all.keys
            JSONObject().apply {
                put("success", true)
                put("keys", JSONArray(keys))
            }
        } catch (e: Exception) {
            errorPayload(e.message ?: "LOCAL_STORAGE_KEYS_FAILED")
        }
        resolve(callbackId, result)
    }

    @JavascriptInterface
    fun postMessage(event: String, payloadJson: String?) {
        val safePayload = payloadJson ?: "null"
        val script = "window.dispatchEvent(new CustomEvent(${JSONObject.quote(event)}, { detail: $safePayload }));"
        webView.post {
            webView.evaluateJavascript(script, null)
        }
    }

    private fun resolve(callbackId: String?, payload: JSONObject) {
        if (callbackId.isNullOrBlank()) return
        val escaped = JSONObject.quote(payload.toString())
        webView.post {
            webView.evaluateJavascript(
                "window.HybridNative&&window.HybridNative.__resolve&&window.HybridNative.__resolve(${JSONObject.quote(callbackId)}, $escaped);",
                null
            )
        }
    }
}

fun successPayload(value: Any?): JSONObject {
    return JSONObject().apply {
        put("success", true)
        put("value", value)
    }
}

fun errorPayload(message: String): JSONObject {
    return JSONObject().apply {
        put("success", false)
        put("error", message)
    }
}